+
+// --- Toast ---
+
+export function useToast() {
+  const [message, setMessage] = useState<string | null>(null);
+  const timerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
+
+  const show = useCallback((msg: string) => {
+    clearTimeout(timerRef.current);
+    setMessage(msg);
+    timerRef.current = setTimeout(() => setMessage(null), 2000);
+  }, []);
+
+  useEffect(() => () => clearTimeout(timerRef.current), []);
+
+  return { message, show };
+}
+
+export function Toast({ message }: { message: string | null }) {
+  if (!message) return null;
+  return (
+    <div className="toast fixed bottom-6 right-6 z-50 rounded-lg bg-ink px-4 py-2.5 text-sm text-white shadow-lg">
+      {message}
+    </div>
+  );
+}
+
+// --- Confirm Modal ---
+
+interface ConfirmModalProps {
+  title: string;
+  message: string;
+  confirmLabel?: string;
+  danger?: boolean;
+  onConfirm: () => void;
+  onCancel: () => void;
+}
+
+export function ConfirmModal({
+  title,
+  message,
+  confirmLabel = "Confirm",
+  danger = false,
+  onConfirm,
+  onCancel,
+}: ConfirmModalProps) {
+  useEffect(() => {
+    function handleKeyDown(e: KeyboardEvent) {
+      if (e.key === "Escape") onCancel();
+    }
+    document.addEventListener("keydown", handleKeyDown);
+    return () => document.removeEventListener("keydown", handleKeyDown);
+  }, [onCancel]);
+
+  return (
+    <div
+      className="fixed inset-0 z-50 flex items-center justify-center bg-black/30"
+      onClick={onCancel}
+    >
+      <div
+        className="w-full max-w-sm bg-white border border-edge rounded-lg p-6"
+        onClick={(e) => e.stopPropagation()}
+      >
+        <h2 className="heading-display text-lg mb-2">{title}</h2>
+        <p className="text-sm text-slate mb-5">{message}</p>
+        <div className="flex items-center gap-3">
+          <button
+            className={danger ? "btn-danger" : "btn-primary"}
+            onClick={onConfirm}
+          >
+            {confirmLabel}
+          </button>
+          <button className="btn-secondary" onClick={onCancel}>
+            Cancel
+          </button>
+        </div>
+      </div>
+    </div>
+  );
+}
